<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Snake</title>
<style>
  * { box-sizing: border-box; }
  html, body { height: 100%; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 18px;
    background:
      radial-gradient(900px 600px at 50% -10%, rgba(56,189,248,.12), transparent 60%),
      radial-gradient(700px 500px at 80% 110%, rgba(74,222,128,.10), transparent 60%),
      #0a0f1c;
    color: #e6edf3;
    font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
    -webkit-font-smoothing: antialiased;
    user-select: none;
  }
  h1 {
    margin: 0;
    font-size: 28px;
    letter-spacing: .5em;
    text-indent: .5em;
    color: #7dd3fc;
    text-shadow: 0 0 18px rgba(125,211,252,.45);
  }
  .hud {
    display: flex;
    align-items: baseline;
    gap: 14px;
  }
  .hud .label {
    font-size: 13px;
    letter-spacing: .3em;
    color: #8ea2bd;
  }
  #score {
    font-size: 34px;
    font-weight: 800;
    color: #4ade80;
    text-shadow: 0 0 14px rgba(74,222,128,.5);
    min-width: 2ch;
  }
  .frame {
    padding: 10px;
    border-radius: 16px;
    background: linear-gradient(145deg, rgba(148,163,184,.14), rgba(148,163,184,.03));
    box-shadow: 0 20px 60px rgba(0,0,0,.55), inset 0 1px 0 rgba(255,255,255,.06);
  }
  #snake {
    display: block;
    width: 400px;
    height: 400px;
    border-radius: 10px;
    background: #0d1424;
    box-shadow: inset 0 0 0 1px rgba(125,211,252,.12);
  }
  .controls { display: flex; gap: 12px; }
  button {
    font: inherit;
    font-size: 13px;
    font-weight: 700;
    letter-spacing: .14em;
    text-transform: uppercase;
    padding: 10px 24px;
    border-radius: 999px;
    border: none;
    cursor: pointer;
    color: #0a0f1c;
    transition: transform .08s ease, filter .15s ease, box-shadow .2s ease;
  }
  button:hover { filter: brightness(1.12); }
  button:active { transform: scale(.94); }
  #start { background: #4ade80; box-shadow: 0 0 18px rgba(74,222,128,.35); }
  #pause { background: #fbbf24; box-shadow: 0 0 18px rgba(251,191,36,.28); }
  #reset { background: #fb7185; box-shadow: 0 0 18px rgba(251,113,133,.28); }
  .hint {
    margin: 0;
    font-size: 11px;
    letter-spacing: .18em;
    color: #64748b;
  }
</style>
</head>
<body>
  <h1>SNAKE</h1>
  <div class="hud"><span class="label">SCORE</span><span id="score">0</span></div>
  <div class="frame"><canvas id="snake" width="400" height="400"></canvas></div>
  <div class="controls">
    <button id="start" type="button">Start</button>
    <button id="pause" type="button">Pause</button>
    <button id="reset" type="button">Reset</button>
  </div>
  <p class="hint">ARROWS / WASD — steer &nbsp;·&nbsp; SPACE — pause</p>

<script>
(function () {
  "use strict";

  var COLS = 20, ROWS = 20, CELL = 20;          // 20x20 grid, 400x400 board
  var W = COLS * CELL, H = ROWS * CELL;
  var DIRS = { up: [0, -1], down: [0, 1], left: [-1, 0], right: [1, 0] };
  var OPP  = { up: 'down', down: 'up', left: 'right', right: 'left' };

  var canvas = document.getElementById('snake');
  var ctx = canvas.getContext('2d');
  var dpr = Math.max(1, Math.min(2, window.devicePixelRatio || 1));
  canvas.width = W * dpr;
  canvas.height = H * dpr;
  ctx.scale(dpr, dpr);

  var scoreEl = document.getElementById('score');

  var snakeArr, dir, dirQueue, foodPos, scoreVal, isAlive, tickCount;
  var timer = null;
  var speed = 135;

  function reset() {
    var cy = Math.floor(ROWS / 2);
    snakeArr = [[8, cy], [7, cy], [6, cy]];      // head first, length 3
    dir = 'right';
    dirQueue = [];
    scoreVal = 0;
    isAlive = true;
    tickCount = 0;
    speed = 135;
    stopTimer();
    placeFood();
    updateScore();
    draw();
  }

  function placeFood() {
    var occ = {};
    for (var i = 0; i < snakeArr.length; i++) occ[snakeArr[i][0] + ',' + snakeArr[i][1]] = true;
    var free = [];
    for (var y = 0; y < ROWS; y++)
      for (var x = 0; x < COLS; x++)
        if (!occ[x + ',' + y]) free.push([x, y]);
    foodPos = free.length ? free[(Math.random() * free.length) | 0] : null;
  }

  function setFood(x, y) {
    foodPos = [Math.trunc(x), Math.trunc(y)];
    draw();
  }

  function setDir(d) {
    if (!DIRS[d]) return;
    var last = dirQueue.length ? dirQueue[dirQueue.length - 1] : dir;
    if (d === last || OPP[d] === last) return;    // ignore duplicates & 180° reversals
    if (dirQueue.length < 3) dirQueue.push(d);
  }

  function tick() {
    if (!isAlive) return;
    while (dirQueue.length) {
      var nd = dirQueue.shift();
      if (nd !== dir && OPP[nd] !== dir) { dir = nd; break; }
    }
    var d = DIRS[dir];
    var head = snakeArr[0];
    var nx = head[0] + d[0], ny = head[1] + d[1];

    if (nx < 0 || ny < 0 || nx >= COLS || ny >= ROWS) { die(); return; }   // wall

    var eating = foodPos && nx === foodPos[0] && ny === foodPos[1];
    var limit = eating ? snakeArr.length : snakeArr.length - 1;            // tail moves away unless eating
    for (var i = 0; i < limit; i++)
      if (snakeArr[i][0] === nx && snakeArr[i][1] === ny) { die(); return; } // self

    snakeArr.unshift([nx, ny]);
    if (eating) {
      scoreVal++;
      updateScore();
      speed = Math.max(65, 135 - scoreVal * 4);
      if (timer !== null) runLoop();
      placeFood();
    } else {
      snakeArr.pop();
    }
    tickCount++;
    draw();
  }

  function die() {
    isAlive = false;
    stopTimer();
    draw();
  }

  function updateScore() { scoreEl.textContent = String(scoreVal); }

  function runLoop() {
    stopTimer();
    timer = setInterval(tick, speed);
  }
  function stopTimer() {
    if (timer !== null) { clearInterval(timer); timer = null; }
  }
  function start() {
    if (!isAlive) reset();
    if (timer !== null) return;
    runLoop();
    draw();
  }
  function pause() {
    stopTimer();
    draw();
  }

  function rr(x, y, w, h, r) {
    r = Math.min(r, w / 2, h / 2);
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.arcTo(x + w, y, x + w, y + h, r);
    ctx.arcTo(x + w, y + h, x, y + h, r);
    ctx.arcTo(x, y + h, x, y, r);
    ctx.arcTo(x, y, x + w, y, r);
    ctx.closePath();
  }

  function panel(title, sub) {
    var pw = 300, ph = 104, px = (W - pw) / 2, py = (H - ph) / 2;
    ctx.fillStyle = 'rgba(5,9,18,0.82)';
    rr(px, py, pw, ph, 14);
    ctx.fill();
    ctx.strokeStyle = 'rgba(125,211,252,0.35)';
    ctx.lineWidth = 1.5;
    ctx.stroke();
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#e6edf3';
    ctx.font = '700 30px ui-monospace, Menlo, Consolas, monospace';
    ctx.fillText(title, W / 2, py + 40);
    ctx.fillStyle = '#9fb0c7';
    ctx.font = '12px ui-monospace, Menlo, Consolas, monospace';
    ctx.fillText(sub, W / 2, py + 72);
  }

  function draw() {
    ctx.fillStyle = '#0d1424';
    ctx.fillRect(0, 0, W, H);

    ctx.strokeStyle = 'rgba(148,163,184,0.07)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (var i = 1; i < COLS; i++) { ctx.moveTo(i * CELL + 0.5, 0); ctx.lineTo(i * CELL + 0.5, H); }
    for (var j = 1; j < ROWS; j++) { ctx.moveTo(0, j * CELL + 0.5); ctx.lineTo(W, j * CELL + 0.5); }
    ctx.stroke();

    if (foodPos) {
      var fx = foodPos[0] * CELL + CELL / 2, fy = foodPos[1] * CELL + CELL / 2;
      ctx.save();
      ctx.shadowColor = 'rgba(244,63,94,0.9)';
      ctx.shadowBlur = 16;
      ctx.fillStyle = '#fb7185';
      ctx.beginPath();
      ctx.arc(fx, fy, CELL * 0.34, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
      ctx.fillStyle = 'rgba(255,255,255,0.55)';
      ctx.beginPath();
      ctx.arc(fx - 2.5, fy - 3, 2, 0, Math.PI * 2);
      ctx.fill();
    }

    var n = snakeArr.length;
    for (var k = n - 1; k >= 0; k--) {
      var sx = snakeArr[k][0] * CELL, sy = snakeArr[k][1] * CELL;
      var t = n <= 1 ? 0 : k / (n - 1);
      var r = Math.round(74 + (20 - 74) * t);
      var g = Math.round(222 + (120 - 222) * t);
      var b = Math.round(128 + (58 - 128) * t);
      ctx.fillStyle = 'rgb(' + r + ',' + g + ',' + b + ')';
      rr(sx + 1.5, sy + 1.5, CELL - 3, CELL - 3, k === 0 ? 7 : 5);
      ctx.fill();
    }

    var hx = snakeArr[0][0] * CELL, hy = snakeArr[0][1] * CELL;
    var eyes = {
      right: [[13.5, 6.5], [13.5, 13.5]],
      left:  [[6.5, 6.5],  [6.5, 13.5]],
      up:    [[6.5, 6.5],  [13.5, 6.5]],
      down:  [[6.5, 13.5], [13.5, 13.5]]
    }[dir];
    ctx.fillStyle = '#052e16';
    for (var e = 0; e < eyes.length; e++) {
      ctx.beginPath();
      ctx.arc(hx + eyes[e][0], hy + eyes[e][1], 2.2, 0, Math.PI * 2);
      ctx.fill();
    }

    if (!isAlive) {
      panel('GAME OVER', 'score ' + scoreVal + '  ·  press start to play again');
    } else if (timer === null && tickCount === 0) {
      panel('SNAKE', 'arrow keys or press start');
    }
  }

  var KEYMAP = {
    ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
    w: 'up', s: 'down', a: 'left', d: 'right',
    W: 'up', S: 'down', A: 'left', D: 'right'
  };
  window.addEventListener('keydown', function (e) {
    var d = KEYMAP[e.key];
    if (d) {
      e.preventDefault();
      setDir(d);
      if (timer === null && isAlive) start();
      return;
    }
    if (e.key === ' ') {
      e.preventDefault();
      if (timer !== null) pause(); else start();
    } else if (e.key === 'Enter') {
      if (timer === null) start();
    }
  });

  function bind(id, fn) {
    var el = document.getElementById(id);
    el.addEventListener('click', function () { fn(); el.blur(); });
  }
  bind('start', start);
  bind('pause', pause);
  bind('reset', reset);

  window.game = {
    w: COLS,
    h: ROWS,
    reset: reset,
    tick: tick,
    setDir: setDir,
    setFood: setFood,
    snake: function () {
      return snakeArr.map(function (p) { return [p[0], p[1]]; });
    },
    food: function () { return foodPos ? [foodPos[0], foodPos[1]] : null; },
    alive: function () { return isAlive; },
    score: function () { return scoreVal; }
  };

  reset();
})();
</script>
</body>
</html>
